minimalFix:
For Symptom 1 (Duplicate Task Processing):
To fix the stale `_cachedEntries` in `scheduler.js`, `pickNextTask` must always fetch the current state of the priority queue.

File: `src/scheduler.js`
```javascript
// Remove the module-scoped _cachedEntries initialization
// const _cachedEntries = getEntries(); 

export async function pickNextTask() {
    // Fetch current entries every time
    const currentEntries = getEntries(); 
    if (currentEntries.length === 0) return null;

    let bestIdx = 0;
    for (let i = 1; i < currentEntries.length; i++) {
        if (currentEntries[i].priority > currentEntries[bestIdx].priority) {
            bestIdx = i;
        }
    }
    const task = currentEntries[bestIdx];

    await verifyTaskNotCancelled(task.id);
    removeById(task.id);
    _assignmentCount++;
    return task;
}

// Update getSchedulerDiagnostics as _cachedEntries is removed
export function getSchedulerDiagnostics() {
    return {
        assignmentCount: _assignmentCount,
        // cachedEntriesLength: _cachedEntries.length, // REMOVE this line
        queueDiagnostics: getDiagnostics(),
    };
}
```

For Symptom 2 (Missing Metrics on Shutdown):
The `flushMetrics` call in `shutdown` must be awaited to ensure metrics are sent before process exit.

File: `src/index.js`
```javascript
export async function shutdown() {
    console.log('[Service] Shutting down...');
    stopRebalanceCycle();
    stopHealthMonitor();

    // Await flushMetrics to ensure completion
    await flushMetrics();

    await drainPool();
    console.log('[Service] Shutdown complete.');
}
```

